const combo = $input.first().json;
const topic = combo.topic;
const client = combo.client;
const analysis = combo.websiteAnalysis;

const prompt = `Du bist ein erfahrener E-Mail Marketing Texter für E-Commerce.

AUFGABE: Schreibe einen Newsletter für ${client.firmenname}.

THEMA: ${topic.name}

KONTEXT AUS NOTION:
${topic.notionContent}

WEBSITE-ANALYSE:
- Produktkategorie: ${analysis.mainProduct}
- Tonality: ${analysis.tone}
- USP: ${analysis.usp}
- Garantie/Versprechen: ${analysis.guarantee}

ANFORDERUNGEN:
1. Betreffzeile (max 60 Zeichen, catchy)
2. Preview Text (max 100 Zeichen)
3. E-Mail Body (HTML, professionell, im Stil der Marke)
4. CTA Text (kurz, action-orientiert)

Der Text soll ${analysis.tone === 'luxury' ? 'elegant und exklusiv' : analysis.tone === 'casual' ? 'locker und sympathisch' : 'professionell und vertrauenswürdig'} wirken.

Antworte im JSON Format:
{
  "subject": "...",
  "previewText": "...",
  "emailBody": "... (HTML mit <p>, <h2>, <ul>, <li>, <strong>, <em>) ...",
  "ctaText": "..."
}`;

return [{
  json: {
    ...combo,
    aiPrompt: prompt
  }
}];

const combo = $input.first().json;
const aiResponse = combo.body;

if (!aiResponse || !aiResponse.content || !aiResponse.content[0]) {
  return [{
    json: {
      ...combo,
      generatedContent: {
        subject: `${combo.topic.name} | ${combo.client.firmenname}`,
        previewText: `Neue ${combo.websiteAnalysis?.mainProduct || 'Produkte'} entdecken`,
        emailBody: `<p>Hallo!</p><p>Wir haben spannende Neuigkeiten zu ${combo.topic.name}.</p><p>Entdecke mehr auf unserer Website.</p>`,
        ctaText: 'Jetzt entdecken'
      },
      aiError: 'AI generation failed, using fallback'
    }
  }];
}

try {
  const text = aiResponse.content[0].text;
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  const parsed = JSON.parse(jsonMatch ? jsonMatch[0] : text);

  return [{
    json: {
      ...combo,
      generatedContent: {
        subject: parsed.subject || `${combo.topic.name} | ${combo.client.firmenname}`,
        previewText: parsed.previewText || `Neue ${combo.websiteAnalysis?.mainProduct || 'Produkte'}`,
        emailBody: parsed.emailBody || parsed.body || parsed.content || '<p>Content coming soon</p>',
        ctaText: parsed.ctaText || 'Jetzt entdecken'
      }
    }
  }];
} catch (e) {
  return [{
    json: {
      ...combo,
      generatedContent: {
        subject: `${combo.topic.name} | ${combo.client.firmenname}`,
        previewText: `Neue ${combo.websiteAnalysis?.mainProduct || 'Produkte'} entdecken`,
        emailBody: `<p>${aiResponse.content[0].text.substring(0, 500)}</p>`,
        ctaText: 'Mehr erfahren'
      },
      aiError: e.message
    }
  }];
}

const combo = $input.first().json;
const client = combo.client;
const content = combo.generatedContent;
const analysis = combo.websiteAnalysis;

const fullHtml = `<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>${combo.topic.name}</title>
</head>
<body style="font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Helvetica, Arial, sans-serif; line-height: 1.7; color: #222; max-width: 600px; margin: 0 auto; padding: 0;">

<div style="display: none; max-height: 0; overflow: hidden;">${content.previewText}</div>

<div style="background: #000; color: #fff; padding: 40px 30px; text-align: center;">
<h1 style="font-size: 28px; margin: 0 0 10px 0; font-weight: 600;">${client.firmenname}</h1>
<p style="font-size: 14px; margin: 0; opacity: 0.8; text-transform: uppercase; letter-spacing: 2px;">${combo.topic.name}</p>
</div>

<div style="padding: 40px 30px;">
${content.emailBody}
</div>

<div style="background: #f5f5f5; padding: 40px 30px; text-align: center;">
<a href="${client.website}" style="display: inline-block; background: #000; color: #fff; padding: 16px 40px; text-decoration: none; border-radius: 4px; font-weight: 600; font-size: 15px; text-transform: uppercase; letter-spacing: 1px;">${content.ctaText} →</a>
<p style="font-size: 13px; color: #888; margin-top: 20px;">${analysis?.guarantee || ''}</p>
</div>

<div style="padding: 30px; text-align: center; color: #999; font-size: 12px; border-top: 1px solid #eee;">
<p style="margin: 0 0 10px 0;"><strong style="color: #333;">${client.firmenname}</strong></p>
<p style="margin: 15px 0;"><a href="${client.website}" style="color: #666;">${client.website}</a></p>
</div>

</body>
</html>`;

return [{
  json: {
    ...combo,
    finalEmail: {
      subject: content.subject,
      previewText: content.previewText,
      html: fullHtml
    }
  }
}];

const combo = $input.first().json;
const client = combo.client;

try {
  const resp = await $httpRequest({
    method: 'GET',
    url: 'https://a.klaviyo.com/api/lists',
    headers: {
      'Authorization': `Klaviyo-API-Key ${client.klaviyoKey}`,
      'revision': '2024-10-15'
    }
  });

  const lists = resp.body?.data || [];
  let targetList = lists[0]?.id;

  for (const list of lists) {
    const name = list.attributes?.name?.toLowerCase() || '';
    if (name.includes('newsletter') || name.includes('main') || name.includes('all')) {
      targetList = list.id;
      break;
    }
  }

  return [{
    json: {
      ...combo,
      targetList: targetList
    }
  }];
} catch (e) {
  return [{
    json: {
      ...combo,
      targetList: null,
      klaviyoError: e.message
    }
  }];
}

const combo = $input.first().json;
const client = combo.client;
const email = combo.finalEmail;
const topic = combo.topic;

const topicDate = topic.date;
const today = new Date();
let sendDate;

if (topicDate) {
  const d = new Date(topicDate);
  sendDate = d < today ? new Date(d.setDate(d.getDate() + 7)) : d;
} else {
  sendDate = new Date(today.setDate(today.getDate() + 1));
}

const sendAt = sendDate.toISOString().split('T')[0] + 'T09:00:00.000Z';

const campaignData = {
  data: {
    type: 'campaign',
    attributes: {
      name: email.subject,
      audiences: { included: combo.targetList ? [combo.targetList] : [] },
      send_strategy: {
        method: 'static',
        options_static: { datetime: sendAt }
      },
      'campaign-messages': {
        data: [{
          type: 'campaign-message',
          attributes: {
            channel: 'email',
            label: email.subject.slice(0, 50),
            content: {
              subject: email.subject,
              preview_text: email.previewText
            }
          }
        }]
      }
    }
  }
};

try {
  const resp = await $httpRequest({
    method: 'POST',
    url: 'https://a.klaviyo.com/api/campaigns',
    headers: {
      'Authorization': `Klaviyo-API-Key ${client.klaviyoKey}`,
      'revision': '2024-10-15',
      'Content-Type': 'application/json'
    },
    body: campaignData
  });

  return [{
    json: {
      comboId: combo.comboId,
      client: client.firmenname,
      topic: topic.name,
      subject: email.subject,
      campaignId: resp.body?.data?.id,
      status: 'Created',
      sendDate: sendAt
    }
  }];
} catch (e) {
  return [{
    json: {
      comboId: combo.comboId,
      client: client.firmenname,
      topic: topic.name,
      subject: email.subject,
      campaignId: null,
      status: 'Failed',
      error: e.message
    }
  }];
}

const results = $input.all();
const campaigns = results.map(r => r.json);

const success = campaigns.filter(c => c.campaignId).length;
const failed = campaigns.length - success;

const summary = {};
for (const c of campaigns) {
  if (!summary[c.client]) summary[c.client] = { success: 0, failed: 0 };
  if (c.campaignId) summary[c.client].success++;
  else summary[c.client].failed++;
}

return [{
  json: {
    success,
    failed,
    total: campaigns.length,
    summary,
    date: new Date().toLocaleDateString('de-DE'),
    campaigns: campaigns.slice(0, 10)
  }
}];

